            // (-r) (+I) coordinates are :
            // cos (theta), sin (theta) sin (phi2), sin (theta) cos (phi2)
            // and we can choose to have theta in the interval [0 ; PI]
            final FieldVector3D<T> v1 = applyTo(vector(1, 0, 0));
            final FieldVector3D<T> v2 = applyInverseTo(vector(1, 0, 0));
