            }
            return buildArray(v1.getZ().atan2(v1.getY()),
                              v2.getX().acos(),
                              v2.getZ().atan2(v2.getY().negate()));

        } else if (order == RotationOrder.YXY) {

            // r (+J) coordinates are :
            //  sin (theta1) sin (phi), cos (phi), cos (theta1) sin (phi)
