            throw MathRuntimeException.createIllegalArgumentException(
                  LocalizedFormats.WRONG_NUMBER_OF_POINTS, 2, x.length);
        }

        // Number of intervals.  The number of data points is n + 1.
        int n = x.length - 1;

        for (int i = 0; i < n; i++) {
            if (x[i] >= x[i + 1]) {
